html:
{% set practitioner = frappe.get_doc("Healthcare Practitioner", doc.practitioner) if doc.practitioner else None %}
{% set patient = frappe.get_doc("Patient", doc.patient) if doc.patient else None %}

<style>
    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;700&display=swap');

    .prescription-container {
        font-family: 'Inter', Arial, sans-serif;
        padding: 40px;
        color: #333;
        position: relative;
        min-height: 1000px;
        background-color: white;
    }

    .header {
        display: flex;
        justify-content: space-between;
        align-items: flex-start;
        margin-bottom: 20px;
    }

    .logo-section {
        display: flex;
        flex-direction: column;
    }

    .logo-container {
        display: flex;
        align-items: center;
        gap: 10px;
        margin-bottom: 5px;
    }

    .s2w-icon {
        width: 40px;
        height: 40px;
        border-radius: 50%;
        background-color: #8BC34A;
        color: white;
        display: flex;
        align-items: center;
        justify-content: center;
        font-weight: bold;
        font-size: 18px;
    }

    .logo-text {
        font-size: 24px;
        font-weight: 700;
        letter-spacing: -1px;
    }

    .wellness-banner {
        background-color: #8BC34A;
        color: white;
        padding: 4px 12px;
        font-size: 10px;
        font-weight: 700;
        text-transform: uppercase;
        width: fit-content;
    }

    .practitioner-info {
        text-align: right;
    }

    .practitioner-info h1 {
        margin: 0;
        font-size: 18px;
        font-weight: 700;
    }

    .practitioner-info p {
        margin: 2px 0;
        font-size: 12px;
    }

    .divider {
        border-top: 1px solid #000;
        margin: 15px 0;
        width: 100%;
    }

    .address-section {
        display: flex;
        justify-content: space-between;
        font-size: 11px;
        margin-bottom: 15px;
    }

    .patient-info-row {
        display: flex;
        flex-wrap: wrap;
        gap: 15px;
        padding: 8px 0;
        font-size: 13px;
        border-top: 1px solid #000;
        border-bottom: 1px solid #000;
        margin-bottom: 5px;
    }

    .patient-address-row {
        font-size: 11px;
        padding: 4px 0;
        margin-bottom: 10px;
        color: #555;
    }

    .diagnosis-section {
        font-size: 12px;
        margin-bottom: 10px;
        padding: 5px 0;
        border-bottom: 1px solid #ddd;
    }

    .prescription-body {
        position: relative;
        min-height: 350px;
        padding: 15px 0;
        background-image: radial-gradient(#8BC34A33 1px, transparent 1px);
        background-size: 20px 20px;
    }

    .medication-table {
        width: 100%;
        border-collapse: collapse;
    }

    .medication-table td {
        padding: 10px 0;
        vertical-align: top;
        font-size: 13px;
    }

    .medication-name {
        font-weight: 700;
        font-size: 14px;
    }

    .med-detail {
        font-size: 11px;
        margin-top: 2px;
    }

    .footer {
        position: absolute;
        bottom: 40px;
        left: 40px;
        right: 40px;
        display: flex;
        justify-content: space-between;
        align-items: flex-end;
    }

    .signature-area {
        width: 250px;
    }

    .signature-img {
        max-width: 150px;
        max-height: 50px;
        margin-bottom: 5px;
    }

    .signature-line {
        border-top: 1px solid #000;
        margin-bottom: 5px;
    }

    .contact-details {
        text-align: right;
        font-size: 12px;
    }

    .contact-item {
        display: flex;
        align-items: center;
        justify-content: flex-end;
        gap: 8px;
        margin-bottom: 5px;
    }

    .icon-circle {
        width: 18px;
        height: 18px;
        border-radius: 50%;
        background-color: #000;
        color: white;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 10px;
    }

    .bottom-accent {
        position: absolute;
        bottom: 0;
        right: 0;
        width: 100px;
        height: 8px;
        background-color: #8BC34A;
    }
</style>

<div class="prescription-container">
    <div class="header">
        <div class="logo-section">
            <div class="logo-container">
                <div class="s2w-icon">S2W</div>
                <div class="logo-text">slim 2 well</div>
            </div>
            <div class="wellness-banner">WELLNESS SIMPLIFIED</div>
        </div>
        <div class="practitioner-info">
            <h1>Prescription/Voorskrif</h1>
            <p><strong>Dr. {{ practitioner.practitioner_name if practitioner else 'N/A' }}</strong></p>
            <p>{{ practitioner.qualification or '' if practitioner else '' }}</p>
            <p><strong>PR: {{ practitioner.practice_number or 'N/A' if practitioner else 'N/A' }}</strong></p>
            <p>SAMDC {{ practitioner.hpcsa_registration_number or 'N/A' if practitioner else 'N/A' }}</p>
        </div>
    </div>

    <div class="divider"></div>

    <div class="address-section">
        <div class="physical-address">
            {% if practitioner and practitioner.practice_address %}
                {{ practitioner.practice_address.replace('\n', '<br>') }}
            {% elif practitioner and practitioner.practitioner_primary_address %}
                {% set p_addr = frappe.get_doc('Address', practitioner.practitioner_primary_address) %}
                {{ p_addr.address_line1 or '' }}<br>
                {% if p_addr.address_line2 %}{{ p_addr.address_line2 }}<br>{% endif %}
                {{ p_addr.city or '' }}
            {% else %}
                N/A
            {% endif %}
        </div>
        <div class="postal-address" style="text-align: right;">
            {% set postal = practitioner.practitioner_postal_address if practitioner else None %}
            {% if postal %}
                {{ postal.replace('\n', '<br>') }}
            {% endif %}
        </div>
    </div>

    <!-- Patient identification row -->
    <div class="patient-info-row">
        <div><strong>Patient:</strong> {{ doc.patient_name or '____________________' }}</div>
        <div><strong>ID:</strong> {{ patient.uid if patient and patient.uid else '____________________' }}</div>
        <div><strong>DOB:</strong> {{ frappe.utils.formatdate(patient.dob) if patient and patient.dob else '________' }}</div>
        <div><strong>Date:</strong> {{ frappe.utils.formatdate(doc.encounter_date or frappe.utils.today()) }}</div>
    </div>

    <!-- Patient address -->
    <div class="patient-address-row">
        <strong>Address:</strong>
        {%- if patient -%}
            {%- set addresses = frappe.get_all('Address', filters=[['Dynamic Link', 'link_doctype', '=', 'Patient'], ['Dynamic Link', 'link_name', '=', patient.name]], fields=['*'], order_by='is_primary_address DESC', limit=1) -%}
            {%- if addresses -%}
                {{ addresses[0].address_line1 or '' }}
                {%- if addresses[0].address_line2 %}, {{ addresses[0].address_line2 }}{% endif -%}
                {%- if addresses[0].city %}, {{ addresses[0].city }}{% endif -%}
                {%- if addresses[0].pincode %} {{ addresses[0].pincode }}{% endif -%}
            {%- else -%}
                N/A
            {%- endif -%}
        {%- else -%}
            N/A
        {%- endif -%}
    </div>

    <!-- Diagnosis / ICD-10 -->
    {%- if doc.diagnosis or doc.codification_table -%}
    <div class="diagnosis-section">
        <strong>Diagnosis:</strong>
        {%- if doc.diagnosis -%}
            {%- for diag in doc.diagnosis -%}{{ diag.diagnosis }}{%- if not loop.last -%}, {%- endif -%}{%- endfor -%}
        {%- endif -%}
        {%- if doc.codification_table -%}
            &nbsp;(ICD-10: {%- for code in doc.codification_table -%}{{ code.code }}{%- if not loop.last -%}, {%- endif -%}{%- endfor -%})
        {%- endif -%}
    </div>
    {%- endif -%}

    <div class="prescription-body">
        <table class="medication-table">
            <tbody>
                {% if doc.drug_prescription %}
                    {% for med in doc.drug_prescription %}
                        <tr>
                            <td>
                                <div class="medication-name">{{ med.drug_name or med.medication }}</div>
                                {%- if med.strength -%}
                                <div class="med-detail">
                                    <strong>Strength:</strong> {{ med.strength }} {{ med.strength_uom or '' }}
                                </div>
                                {%- endif -%}
                                <div class="med-detail">
                                    <strong>Form:</strong> {{ med.dosage_form or 'N/A' }}
                                </div>
                                <div class="med-detail">
                                    <strong>Dose:</strong>
                                    {%- if med.dosage_by_interval -%}
                                        Every {{ med.interval or '' }} {{ med.interval_uom or 'days' }}
                                        {%- if med.dosage %}: {{ med.dosage }}{% endif -%}
                                    {%- else -%}
                                        {{ med.dosage or 'As directed' }}
                                    {%- endif -%}
                                    {% if med.period %} | <strong>Duration:</strong> {{ med.period }}{% endif %}
                                </div>
                                <div class="med-detail">
                                    <strong>Route:</strong>
                                    {%- set med_route = '' -%}
                                    {%- if med.drug_code -%}
                                        {%- set med_item = frappe.get_doc('Item', med.drug_code) -%}
                                        {%- set med_route = med_item.route_of_administration or '' if med_item else '' -%}
                                    {%- endif -%}
                                    {%- if not med_route and med.medication -%}
                                        {%- set med_ref = frappe.get_doc('Medication', med.medication) -%}
                                        {%- if med_ref and med_ref.linked_items -%}
                                            {%- set linked_item = frappe.get_doc('Item', med_ref.linked_items[0].item) -%}
                                            {%- set med_route = linked_item.route_of_administration or '' if linked_item else '' -%}
                                        {%- endif -%}
                                    {%- endif -%}
                                    {{ med_route or 'As directed' }}
                                </div>
                                <div class="med-detail">
                                    <strong>Repeats:</strong>
                                    {%- if med.number_of_repeats_allowed and med.number_of_repeats_allowed > 0 -%}
                                        {{ med.number_of_repeats_allowed|int }} time(s)
                                    {%- else -%}
                                        No repeats
                                    {%- endif -%}
                                </div>
                                {% if med.comment %}
                                    <div class="med-detail" style="font-style: italic; color: #666;">{{ med.comment }}</div>
                                {% endif %}
                            </td>
                        </tr>
                    {% endfor %}
                {% else %}
                    <tr>
                        <td style="color: #ccc; text-align: center; padding-top: 100px;">
                            No medications prescribed.
                        </td>
                    </tr>
                {% endif %}
            </tbody>
        </table>
    </div>

    <div class="footer">
        <div class="signature-area">
            {%- if practitioner and practitioner.custom_signature_image -%}
                <img src="{{ practitioner.custom_signature_image }}" class="signature-img" />
            {%- else -%}
                <div style="height: 40px;"></div>
            {%- endif -%}
            <div class="signature-line"></div>
            <div style="font-size: 12px; font-weight: 700;">
                Dr. {{ practitioner.practitioner_name if practitioner else 'N/A' }} | {{ practitioner.qualification or '' if practitioner else '' }}
            </div>
        </div>

        <div class="contact-details">
            <div class="contact-item">
                {{ practitioner.mobile_phone or practitioner.office_phone or '___________' if practitioner else '___________' }}
                <div class="icon-circle">&#x260E;</div>
            </div>
            <div class="contact-item">
                {{ practitioner.email_id or '___________' if practitioner else '___________' }}
                <div class="icon-circle">&#x2709;</div>
            </div>
        </div>
    </div>

    <div class="bottom-accent"></div>
</div>
